import './App.css';
import {Routes, Route} from 'react-router-dom'
import {routes} from './routes/routes'

function App() {
  return (
  <div className='App'>App
    <Routes>
      {routes.map((route) => {
        <Route 
        key={route.path}/>
      })}
    </Routes>
  </div>
  );
}

export default App;
